                horizontalPrefix[i][j] = (j >= 1 ? horizontalPrefix[i][j - 1] : 0) + 1;
            }
        }

        let mx = 0;
        for (let j = n - 1; j >= 0; j--) {
            if (mat[i][j] === '.') {
                horizontalSuffix[i][j] = 0;
                mx = 0;
            } else {
                horizontalSuffix[i][j] = mx;
                mx += 1;
            }
        }
    }

    // Vertical prefix and suffix
    let verticalPrefix = Array.from({ length: n }, () => Array(n).fill(0));
    let verticalSuffix = Array.from({ length: n }, () => Array(n).fill(0));

    for (let j = 0; j < n; j++) {
        for (let i = 0; i < n; i++) {
            if (mat[i][j] === '.') {
                verticalPrefix[i][j] = 0;
            } else {
                verticalPrefix[i][j] = (i >= 1 ? verticalPrefix[i - 1][j] : 0) + 1;
            }
        }

        let mx = 0;
        for (let i = n - 1; i >= 0; i--) {
            if (mat[i][j] === '.') {
                verticalSuffix[i][j] = 0;
                mx = 0;
            } else {
                verticalSuffix[i][j] = mx;
                mx += 1;
            }
        }
    }

    // Right diagonal prefix and suffix
    let rightDiagonalPrefix = Array.from({ length: n }, () => Array(n).fill(0));
    let rightDiagonalSuffix = Array.from({ length: n }, () => Array(n).fill(0));

    for (let i = 0; i < n; i++) {
        let k = i, j = 0;
        while (k < n && j < n) {
            if (mat[k][j] === '.') {
                rightDiagonalPrefix[k][j] = 0;
            } else {
                rightDiagonalPrefix[k][j] = (k >= 1 && j >= 1 ? rightDiagonalPrefix[k - 1][j - 1] : 0) + 1;
            }
            k++;
            j++;
        }

        k--; j--;
        let mx = 0;
        while (k >= 0 && j >= 0) {
            if (mat[k][j] === '.') {
                rightDiagonalSuffix[k][j] = 0;
                mx = 0;
            } else {
                rightDiagonalSuffix[k][j] = mx;
                mx += 1;
            }
            k--;
            j--;
        }
    }

    for (let i = 0; i < n; i++) {
        let k = 0, j = i;
        while (k < n && j < n) {
            if (mat[k][j] === '.') {
                rightDiagonalPrefix[k][j] = 0;
            } else {
                rightDiagonalPrefix[k][j] = (k >= 1 && j >= 1 ? rightDiagonalPrefix[k - 1][j - 1] : 0) + 1;
            }
            k++;
            j++;
        }

        k--; j--;
        let mx = 0;
        while (k >= 0 && j >= 0) {
            if (mat[k][j] === '.') {
                rightDiagonalSuffix[k][j] = 0;
                mx = 0;
            } else {
                rightDiagonalSuffix[k][j] = mx;
                mx += 1;
            }
            k--;
            j--;
        }
    }

    // Left diagonal prefix and suffix
    let leftDiagonalPrefix = Array.from({ length: n }, () => Array(n).fill(0));
    let leftDiagonalSuffix = Array.from({ length: n }, () => Array(n).fill(0));

    for (let i = 0; i < n; i++) {
        let k = i, j = n - 1;
        while (k < n && j >= 0) {
            if (mat[k][j] === '.') {
                leftDiagonalPrefix[k][j] = 0;
            } else {
                leftDiagonalPrefix[k][j] = (k >= 1 && j + 1 < n ? leftDiagonalPrefix[k - 1][j + 1] : 0) + 1;
            }
            k++;
            j--;
        }

        k--; j++;
        let mx = 0;
        while (k >= 0 && j < n) {
            if (mat[k][j] === '.') {
                leftDiagonalSuffix[k][j] = 0;
                mx = 0;
            } else {
                leftDiagonalSuffix[k][j] = mx;
                mx += 1;
            }
            k--;
            j++;
        }
    }

    for (let i = 0; i < n; i++) {
        let k = 0, j = i;
        while (k < n && j >= 0) {
            if (mat[k][j] === '.') {
                leftDiagonalPrefix[k][j] = 0;
            } else {
                leftDiagonalPrefix[k][j] = (k >= 1 && j + 1 < n ? leftDiagonalPrefix[k - 1][j + 1] : 0) + 1;
            }
            k++;
            j--;
        }

        k--; j++;
        let mx = 0;
        while (k >= 0 && j < n) {
            if (mat[k][j] === '.') {
                leftDiagonalSuffix[k][j] = 0;
                mx = 0;
            } else {
                leftDiagonalSuffix[k][j] = mx;
                mx += 1;
            }
            k--;
            j++;
        }
    }

    // Calculate maximal crosses
    for (let i = 0; i < n; i++) {
        let result = [];
        for (let j = 0; j < n; j++) {
            let mx = Math.max(
                horizontalPrefix[i][j] + horizontalSuffix[i][j],
                verticalPrefix[i][j] + verticalSuffix[i][j],
                rightDiagonalPrefix[i][j] + rightDiagonalSuffix[i][j],
                leftDiagonalPrefix[i][j] + leftDiagonalSuffix[i][j]
            );
            result.push(mx);
        }
        console.log(result.join(' '));
    }
}

